use std::io::{self, Write};

trait Serialise {
    fn to_bytes(&self) -> Vec<u8>;

    // where Self: Sized makes write_to unavailable through &dyn Serialise
    // but available on all concrete types
    fn write_to<W: Write>(&self, writer: &mut W) where Self: Sized {
        let bytes = self.to_bytes();
        writer.write_all(&bytes).unwrap();
    }

    // Object-safe helper: write to a &mut dyn Write
    fn write_to_dyn(&self, writer: &mut dyn Write) -> io::Result<()> {
        writer.write_all(&self.to_bytes())
    }
}

struct Msg(String);

impl Serialise for Msg {
    fn to_bytes(&self) -> Vec<u8> { self.0.as_bytes().to_vec() }
}

fn save(s: &dyn Serialise) {
    s.write_to_dyn(&mut io::stdout()).unwrap();
    println!();
}

fn main() {
    let m = Msg(String::from("hello from dyn"));
    save(&m);
    // Concrete type can still use write_to<W>
    m.write_to(&mut io::stdout());
    println!();
