trait Retry {
    const MAX_RETRIES: u32 = 3;

    fn should_retry(&self, attempt: u32) -> bool {
        attempt < Self::MAX_RETRIES
    }

    fn run_with_retry(&self, mut action: impl FnMut() -> bool) -> bool {
        for attempt in 0..=Self::MAX_RETRIES {
            if action() { return true; }
            if !self.should_retry(attempt) { break; }
        }
        false
    }
}

struct Resilient;
struct Fragile;
struct Default_;

impl Retry for Resilient { const MAX_RETRIES: u32 = 10; }
impl Retry for Fragile   { const MAX_RETRIES: u32 = 1; }
impl Retry for Default_  {} // uses the trait default of 3

fn main() {
    println!("resilient retry at 5: {}", Resilient.should_retry(5));
    println!("fragile retry at 0: {}", Fragile.should_retry(0));
    println!("default retry at 2: {}", Default_.should_retry(2));
}

