// RPITIT (Return Position impl Trait In Traits) is stable since Rust 1.75.
// If you need to support older compilers, use a boxed iterator:

trait Source {
    fn items(&self) -> Vec<i32>;

    // Works on Rust >= 1.75 (RPITIT)
    fn evens(&self) -> impl Iterator<Item = i32> {
        self.items().into_iter().filter(|x| x % 2 == 0)
    }

    // Backward-compat alternative for older Rust: return Box<dyn Iterator>
    fn evens_boxed(&self) -> Box<dyn Iterator<Item = i32>> {
        Box::new(self.items().into_iter().filter(|x| x % 2 == 0))
    }
}

struct Nums;

impl Source for Nums {
    fn items(&self) -> Vec<i32> { vec![1, 2, 3, 4, 5, 6] }
}

fn main() {
    for n in Nums.evens() { println!("{}", n); }
    let sum: i32 = Nums.evens_boxed().sum();
    println!("sum of evens: {}", sum);
}
